	let parsedUrl = URL.parse(currentUrlStr, true, true);
	delete parsedUrl.hash;


	if (parsedUrl.protocol && parsedUrl.protocol != 'http:' && parsedUrl.protocol != 'https:') return null;

	//current url is relative like "abc", "/abc" or "../abc"
